import React, { useEffect, useState } from "react";
import {
  Container,
  Accordion,
  Row,
  Col,
  Table,
  Spinner,
  Badge,
  Alert,
  ProgressBar,
} from "react-bootstrap";
import "bootstrap/dist/css/bootstrap.min.css";

export default function StudentFee() {
  const [feeData, setFeeData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  // -------------------------
  // DATE FORMATTER
  // -------------------------
  const formatDate = (date) => {
    if (!date) return "N/A";
    return new Date(date).toLocaleDateString("en-GB"); // DD/MM/YYYY
  };

  // -------------------------
  // API CALL
  // -------------------------
  useEffect(() => {
    const fetchFee = async () => {
      try {
        const res = await fetch(
          "http://localhost:65000/api/students/getStudentFee",
          {
            credentials: "include",
          }
        );

        if (!res.ok) throw new Error("Failed to fetch fee details");

        const data = await res.json();
        setFeeData(data);
        setLoading(false);
      } catch (err) {
        setError(err.message);
        setLoading(false);
      }
    };

    fetchFee();
  }, []);

  const getStatusBadge = (status) => {
    switch (status) {
      case "paid":
        return <Badge bg="success">Paid</Badge>;
      case "pending":
        return <Badge bg="warning">Pending</Badge>;
      case "overdue":
        return <Badge bg="danger">Overdue</Badge>;
      default:
        return <Badge bg="secondary">{status}</Badge>;
    }
  };

  if (loading)
    return (
      <Container className="text-center my-5">
        <Spinner animation="border" />
        <p>Loading fee details...</p>
      </Container>
    );

  if (error)
    return (
      <Container className="my-5">
        <Alert variant="danger">{error}</Alert>
      </Container>
    );

  const allKeys = feeData.semesterFees.map((_, idx) => idx.toString());

  return (
    <Container className="my-4">
      <h2 className="mb-4 text-center" style={{ color: "#2c3e50" }}>
        Fee Details - {feeData.studentName} ({feeData.studentId})
      </h2>

      <Accordion defaultActiveKey={allKeys} alwaysOpen>
        {feeData.semesterFees.map((semester, index) => (
          <Accordion.Item eventKey={index.toString()} key={semester.semester}>
            <Accordion.Header>
              <Row className="w-100 align-items-center">
                <Col xs={6}>
                  <strong>Semester {semester.semester}</strong>
                </Col>
                <Col xs={6}>
                  <ProgressBar
                    now={
                      ((semester.totalFee - semester.discountedFee) /
                        semester.totalFee) *
                      100
                    }
                    label={`Discount Applied`}
                    variant="info"
                  />
                </Col>
              </Row>
            </Accordion.Header>

            <Accordion.Body>
              <Row className="mb-3">
                <Col xs={6}>
                  <strong>Total Fee:</strong> {semester.totalFee}
                </Col>
                <Col xs={6}>
                  <strong>Discounted Fee:</strong> {semester.discountedFee}
                </Col>
                <Col xs={6}>
                  <strong>Current Payable:</strong>{" "}
                  {semester.currentPayableAmount}
                </Col>
                <Col xs={6}>
                  <strong>Status:</strong> {getStatusBadge(semester.status)}
                </Col>
              </Row>

              {semester.installments.length === 0 ? (
                <p>No installments available.</p>
              ) : (
                <div className="table-responsive">
                  <Table striped bordered hover>
                    <thead className="table-dark">
                      <tr>
                        <th>#</th>
                        <th>Amount</th>
                        <th>Amount Paid</th>
                        <th>Due Date</th>
                        <th>Paid Date</th>
                        <th>Status</th>
                        <th>Fine</th>
                      </tr>
                    </thead>
                    <tbody>
                      {semester.installments.map((inst, idx) => (
                        <tr key={idx}>
                          <td>{inst.installmentNumber}</td>
                          <td>{inst.amount}</td>
                          <td>{inst.amountPaid}</td>
                          <td>{formatDate(inst.dueDate)}</td>
                          <td>{formatDate(inst.paidDate)}</td>
                          <td>{getStatusBadge(inst.status)}</td>
                          <td>{inst.fineAmount}</td>
                        </tr>
                      ))}
                    </tbody>
                  </Table>
                </div>
              )}
            </Accordion.Body>
          </Accordion.Item>
        ))}
      </Accordion>
    </Container>
  );
}
